#include <bits/stdc++.h>
using namespace std;

const int N = 1e6 + 5;

int a[N], q1[N], q2[N], l1, l2, r1 = -1, r2 = -1;

int main()
{
	int n, k;
    cin >> n >> k;
    for(int i = 1; i <= n; i++)
        cin >> a[i];

    for(int i = 1; i < k; i++)
    {
        while(l1 <= r1 && a[q1[r1]] >= a[i]) r1--;
        q1[++r1] = i;
    }
    for(int i = k; i <= n; i++)
    {
        while(l1 <= r1 && a[q1[r1]] >= a[i]) r1--;
        q1[++r1] = i;
        while(q1[l1] <= i - k) l1++;
        cout << a[q1[l1]] << ' ';
    }
    cout << endl;

    for(int i = 1; i < k; i++)
    {
        while(l2 <= r2 && a[q2[r2]] <= a[i]) r2--;
        q2[++r2] = i;
    }
    for(int i = k; i <= n; i++)
    {
        while(l2 <= r2 && a[q2[r2]] <= a[i]) r2--;
        q2[++r2] = i;
        while(q2[l2] <= i - k) l2++;
        cout << a[q2[l2]] << ' ';
    }

	return 0;
}
